def classify_a1c(a1c):
    if a1c < 0 or a1c > 20:
        raise ValueError('A1c value must be between 0 and 20')
    if a1c < 5.7:
        return 'Normal'
    elif a1c < 6.5:
        return 'Pre-diabetes'
    else:
        return 'Diabetes'

def icd10_chapter(code):
    if not isinstance(code, str) or len(code) < 3:
        return 'Invalid'
    chapter_map = {
        'E': 'Endocrine',
        'I': 'Circulatory',
        'J': 'Respiratory',
        'K': 'Digestive'
    }
    return chapter_map.get(code[0].upper(), 'Other')
